mapper.select:
select c.id as chunkId, c.knowledge_base_id as knowledgeBaseId, c.document_id as documentId, kd.title as documentTitle, c.chunk_no as chunkNo, c.effective_content as effectiveContent, 1 - (cv.embedding <=> cast(#{vectorLiteral} as vector)) as vectorScore, 0 as lexicalScore, 0 as finalScore from t_chunk_vector cv join t_chunk c on c.id::text = cv.id join t_knowledge_document kd on kd.id = c.document_id where c.delete_flag = 0 and c.enabled = true and c.embedding_status = 'SUCCESS' and kd.delete_flag = 0 and kd.status = 'ENABLED' and kd.parse_status = 'SUCCESS'
and true
and coalesce(kd.min_rank_level, 0) <= #{rankLevel} and (kd.visibility_scope <> 'SENSITIVE' or exists ( select 1 from t_document_department_auth dda where dda.document_id = kd.id and dda.department_id = #{departmentId} and dda.delete_flag = 0 )) and (kd.visibility_scope <> 'SENSITIVE' or not exists ( select 1 from t_chunk_department_auth cda where cda.chunk_id = c.id and cda.delete_flag = 0 ) or exists ( select 1 from t_chunk_department_auth cda where cda.chunk_id = c.id and cda.department_id = #{departmentId} and cda.delete_flag = 0 ))
and c.knowledge_base_id in
#{kbId}
order by cv.embedding <=> cast(#{vectorLiteral} as vector) limit #{recallLimit}
